const response = $.steps.scrapeTarget.response || {};
const content = (typeof response === 'string') ? response : JSON.stringify(response);

return {
  siteContent: content.slice(0, 20000),
  url: $.input.targetUrl,
  scrapedAt: new Date().toISOString()
};

const d = $.steps.compileSiteData.output;
const url = $.input.targetUrl;

let prompt = 'You are an expert web security auditor. Perform a comprehensive security analysis of the following website.

';
prompt += 'TARGET WEBSITE: ' + url + '
';
prompt += 'SCAN DATE: ' + d.scrapedAt + '

';
prompt += 'SCRAPED WEBSITE DATA:
' + d.siteContent + '

';
prompt += 'SECURITY ANALYSIS REQUIREMENTS:
';
prompt += '1. HTTP Security Headers: Check for Content-Security-Policy, X-Frame-Options, X-Content-Type-Options, Strict-Transport-Security, Referrer-Policy, Permissions-Policy
';
prompt += '2. SSL/TLS: Evaluate HTTPS implementation
';
prompt += '3. Input Validation: Look for forms without CSRF protection, potential XSS vectors
';
prompt += '4. Information Disclosure: Server version headers, debug info, directory listing
';
prompt += '5. Third-Party Dependencies: Identify external scripts, CDNs, known vulnerable libraries
';
prompt += '6. Cookie Security: HttpOnly, Secure, SameSite flags
';
prompt += '7. Content Security: Mixed content issues, inline scripts

';
prompt += 'SEVERITY LEVELS: critical, high, medium, low, informational

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "url": "' + url + '",
';
prompt += '  "scanDate": "' + d.scrapedAt + '",
';
prompt += '  "overallRisk": "critical|high|medium|low",
';
prompt += '  "overallScore": 0,
';
prompt += '  "findings": [
';
prompt += '    {
';
prompt += '      "category": "Security Headers|SSL|Input Validation|Info Disclosure|Dependencies|Cookies|Content",
';
prompt += '      "severity": "critical|high|medium|low|informational",
';
prompt += '      "title": "finding title",
';
prompt += '      "description": "detailed description",
';
prompt += '      "recommendation": "how to fix"
';
prompt += '    }
';
prompt += '  ],
';
prompt += '  "criticalCount": 0,
';
prompt += '  "highCount": 0,
';
prompt += '  "mediumCount": 0,
';
prompt += '  "lowCount": 0,
';
prompt += '  "executiveSummary": "brief overall assessment",
';
prompt += '  "topRecommendations": ["rec 1", "rec 2", "rec 3"]
';
prompt += '}';

return { prompt };

let raw = $.steps.aiAudit.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { url: $.input.targetUrl, overallRisk: 'unknown', overallScore: 0, findings: [], executiveSummary: raw, topRecommendations: [] }; }

const ai = $.steps.parseAI.output;
const url = $.input.targetUrl;

const riskColors = { critical: '#DC2626', high: '#EA580C', medium: '#D97706', low: '#2563EB' };
const riskColor = riskColors[ai.overallRisk] || '#6B7280';

let html = '<div style="font-family: Arial, sans-serif; max-width: 700px; margin: 0 auto;">';
html += '<div style="background: #1F2937; color: white; padding: 24px; border-radius: 8px 8px 0 0;">';
html += '<h1 style="margin:0;">Website Security Audit Report</h1>';
html += '<p style="margin:8px 0 0;">' + url + '</p>';
html += '<p style="margin:4px 0 0; opacity:0.8;">Scan date: ' + (ai.scanDate || new Date().toISOString()) + '</p>';
html += '</div>';

html += '<div style="background: ' + riskColor + '; color: white; padding: 16px; text-align: center;">';
html += '<h2 style="margin:0;">Overall Risk: ' + (ai.overallRisk || 'Unknown').toUpperCase() + ' | Score: ' + (ai.overallScore || 0) + '/100</h2>';
html += '</div>';

html += '<div style="padding: 24px; background: #F9FAFB;">';
html += '<h3>Executive Summary</h3>';
html += '<p>' + (ai.executiveSummary || 'No summary available') + '</p>';

html += '<h3>Findings Summary</h3>';
html += '<p>Critical: ' + (ai.criticalCount || 0) + ' | High: ' + (ai.highCount || 0) + ' | Medium: ' + (ai.mediumCount || 0) + ' | Low: ' + (ai.lowCount || 0) + '</p>';

const findings = ai.findings || [];
findings.forEach((f, i) => {
  const sevColor = riskColors[f.severity] || '#6B7280';
  html += '<div style="border-left: 4px solid ' + sevColor + '; padding: 12px; margin: 12px 0; background: white;">';
  html += '<strong>[' + (f.severity || 'info').toUpperCase() + '] ' + (f.title || 'Finding ' + (i + 1)) + '</strong>';
  html += '<p style="margin: 4px 0;">' + (f.description || '') + '</p>';
  html += '<p style="margin: 4px 0; color: #059669;"><em>Recommendation: ' + (f.recommendation || 'N/A') + '</em></p>';
  html += '</div>';
});

html += '<h3>Top Recommendations</h3><ol>';
(ai.topRecommendations || []).forEach(r => {
  html += '<li>' + r + '</li>';
});
html += '</ol>';

html += '<hr><p style="color: #9CA3AF; font-size: 12px;">Generated by One CLI | Firecrawl + Claude AI</p>';
html += '</div></div>';

const subject = 'Security Audit Report: ' + url + ' [' + (ai.overallRisk || 'Unknown').toUpperCase() + ' Risk]';
return { html, subject };
